starterCode.css:
body {
  margin: 0;
  min-height: 100vh;
  display: grid;
  place-items: center;
  background: #efe9dc;
  font-family: 'Trebuchet MS', sans-serif;
}

.layout {
  width: min(920px, calc(100vw - 32px));
  min-height: 520px;
  padding: 18px;
  border-radius: 24px;
  background: #fffdf8;
  box-shadow: 0 18px 40px rgba(0, 0, 0, 0.08);
}

header,
nav,
main,
aside,
footer {
  border-radius: 18px;
  padding: 20px;
  color: #fffdf8;
  font-weight: 700;
}

header { background: #355070; }
nav { background: #b56576; }
main { background: #6d597a; }
aside { background: #e56b6f; }
footer { background: #eaac8b; color: #3a2416; }

targetCode.css:
body {
  margin: 0;
  min-height: 100vh;
  display: grid;
  place-items: center;
  background: #efe9dc;
  font-family: 'Trebuchet MS', sans-serif;
}

.layout {
  display: grid;
  grid-template-columns: 180px 1fr 220px;
  grid-template-rows: auto 1fr auto;
  gap: 18px;
  width: min(920px, calc(100vw - 32px));
  min-height: 520px;
  padding: 18px;
  border-radius: 24px;
  background: #fffdf8;
  box-shadow: 0 18px 40px rgba(0, 0, 0, 0.08);
}

header,
nav,
main,
aside,
footer {
  border-radius: 18px;
  padding: 20px;
  color: #fffdf8;
  font-weight: 700;
}

header {
  background: #355070;
  grid-column: 1 / 4;
  grid-row: 1;
}

nav {
  background: #b56576;
  grid-column: 1;
  grid-row: 2;
}

main {
  background: #6d597a;
  grid-column: 2;
  grid-row: 2;
}

aside {
  background: #e56b6f;
  grid-column: 3;
  grid-row: 2;
}

footer {
  background: #eaac8b;
  color: #3a2416;
  grid-column: 1 / 4;
  grid-row: 3;
}
